package com.seaquake6324.civitas.domain.population;import static org.junit.jupiter.api.Assertions.*;import com.seaquake6324.civitas.domain.building.*;import java.util.*;import org.junit.jupiter.api.Test;
class PopulationDashboardTest{
 @Test void explainsHousingFamiliesEmploymentAndUnavailableTrendsPrecisely(){UUID city=UUID.randomUUID(),residence=UUID.randomUUID();BuildingRecord home=new BuildingRecord(residence,city,"minecraft:overworld",BuildingPurpose.RESIDENCE,1,2,Set.of(2L),Map.of(),2,BuildingStatus.VALID,1,0,"");CitizenRecord housed=citizen(city,residence,"Baker",60,10),unhoused=citizen(city,null,"",40,70);Household family=new Household(UUID.randomUUID(),city,Set.of(FamilyMemberRef.citizen(housed.id()),FamilyMemberRef.citizen(unhoused.id())),Set.of(UUID.randomUUID()),residence,80,100,1);PopulationDashboard d=PopulationDashboard.from(city,List.of(housed,unhoused),List.of(family),List.of(home),new AgeRules(24000,12,18,35,60),false);assertEquals(2,d.composition().total());assertEquals(2,d.housingCapacity());assertEquals(1,d.housedCitizens());assertEquals(1,d.unassignedCitizens());assertEquals(1,d.employedCitizens());assertEquals(1,d.partneredHouseholds());assertEquals(80,d.averageFoodCoverage());assertEquals(50,d.averageSettlementWillingness());assertTrue(d.limitations().contains(PopulationDashboard.Limitation.UNASSIGNED_RESIDENCE));assertTrue(d.limitations().contains(PopulationDashboard.Limitation.MIGRATION_TREND_NOT_AVAILABLE));assertTrue(d.limitations().contains(PopulationDashboard.Limitation.BIRTH_TREND_NOT_AVAILABLE));}
 @Test void invalidAndInsufficientHousingRemainDistinct(){UUID city=UUID.randomUUID();CitizenRecord c=citizen(city,UUID.randomUUID(),"",50,0);PopulationDashboard d=PopulationDashboard.from(city,List.of(c),List.of(),List.of(),new AgeRules(1,12,18,35,60),true);assertEquals(1,d.invalidResidenceReferences());assertTrue(d.limitations().contains(PopulationDashboard.Limitation.HOUSING_CAPACITY_SHORTFALL));assertTrue(d.truncated());}
 @Test void permanentDeathHistoryExcludesDeadFromLivingComposition(){UUID city=UUID.randomUUID();CitizenRecord alive=citizen(city,null,"",50,0),dead=citizen(city,null,"",50,0).dieOfOldAge(900);PopulationDashboard d=PopulationDashboard.from(city,List.of(alive,dead),List.of(),List.of(),new AgeRules(1,12,18,35,60),false);assertEquals(1,d.composition().total());assertEquals(1,d.permanentDeaths());assertEquals(900,d.latestDeathAtTick());assertFalse(d.limitations().contains(PopulationDashboard.Limitation.DEATH_HISTORY_NOT_ACTIVE));}
 private static CitizenRecord citizen(UUID city,UUID residence,String profession,double settle,double migrate){return new CitizenRecord(UUID.randomUUID(),"Ada","Berg",CitizenRace.HUMAN,"human_0",Gender.FEMALE,18L*24000,0,city,null,residence,null,profession,100,CitizenNeeds.neutral(),Map.of(),Set.of(),settle,migrate,CitizenRuntimeState.VIRTUAL,0,1);}
}
